import{_ as a,o as t,c as n,ai as i}from"./chunks/framework.DyvBZb4W.js";const b=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"en/mods/xuanji-character/changelog.md","filePath":"en/mods/xuanji-character/changelog.md","lastUpdated":1782051941000}'),r={name:"en/mods/xuanji-character/changelog.md"};function l(o,e,d,s,c,h){return t(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><h2 id="_0-13-0-beta" tabindex="-1">0.13.0-beta <a class="header-anchor" href="#_0-13-0-beta" aria-label="Permalink to &quot;0.13.0-beta&quot;">​</a></h2><ul><li>Reworks and retunes a batch of starter, general, and payoff cards so early Encode flow, retuning decisions, and late-engine rewards read more clearly.</li><li>Updates several synergy follow-up cards, event options, and card text so Watch, Bulwark, random bonus tags, reward picks, and Gold routes have clearer feedback.</li><li>Improves card-library handling and related compatibility support, while continuing support for the Slay the Spire 2 <code>v0.103</code> stable line and <code>v0.107</code> beta line.</li></ul><h2 id="_0-10-0-beta" tabindex="-1">0.10.0-beta <a class="header-anchor" href="#_0-10-0-beta" aria-label="Permalink to &quot;0.10.0-beta&quot;">​</a></h2><ul><li>Reworks and expands a batch of cards and relics, including routes for recall, retuning, Energy return, core fission, core shock, momentum, and finishers.</li><li>Updates several event choices and text, and tightens the wording and interaction hints on a number of cards.</li><li>Keeps compatibility handling for the Slay the Spire 2 <code>v0.103</code> stable line and the <code>v0.107</code> beta line.</li></ul><h2 id="_0-4-0-beta" tabindex="-1">0.4.0-beta <a class="header-anchor" href="#_0-4-0-beta" aria-label="Permalink to &quot;0.4.0-beta&quot;">​</a></h2><ul><li>Adds a broad card and relic refresh, including new card-enchantment, shop, Gold, encoding, condensing, exhaust-defense, Gold-tier burst, and damage-reflection routes.</li><li>Adds multiplayer-focused cards, giving Xuanji more co-op and interaction options in multiplayer runs.</li><li>Refreshes Xuanji&#39;s combat, merchant, rest-site, and Machine Core visuals.</li><li>Keeps compatibility handling for the Slay the Spire 2 <code>v0.103</code> stable line and the <code>v0.106</code> beta line.</li></ul><h2 id="_0-3-0-beta" tabindex="-1">0.3.0-beta <a class="header-anchor" href="#_0-3-0-beta" aria-label="Permalink to &quot;0.3.0-beta&quot;">​</a></h2><ul><li>Adds anonymous run telemetry for future balance tuning, including card picks, final decks, enabled mods, and card play counts.</li></ul><h2 id="v0-2-1-beta" tabindex="-1">v0.2.1-beta <a class="header-anchor" href="#v0-2-1-beta" aria-label="Permalink to &quot;v0.2.1-beta&quot;">​</a></h2><ul><li>Fixes a Beta v0.105.0 game-version startup issue where the mod could fail to load.</li></ul><h2 id="v0-2-0-beta" tabindex="-1">v0.2.0-beta <a class="header-anchor" href="#v0-2-0-beta" aria-label="Permalink to &quot;v0.2.0-beta&quot;">​</a></h2><ul><li>Opens the Xuanji Beta preview, adding a custom character built around Encode, the Machine Chamber, Machine Core condensing, and 8 main synergies.</li><li>Adds Xuanji&#39;s custom cards, custom relics, in-combat Machine Chamber/Core display, and baseline English and Simplified Chinese text.</li></ul><h2 id="v0-1-0" tabindex="-1">v0.1.0 <a class="header-anchor" href="#v0-1-0" aria-label="Permalink to &quot;v0.1.0&quot;">​</a></h2><ul><li>Establishes the Xuanji character prototype and early Encode/synergy gameplay framework.</li></ul>',15)])])}const m=a(r,[["render",l]]);export{b as __pageData,m as default};
